INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05370', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「昔者，海鳥止於魯郊。魯侯御而觴之於廟，奏九韶以為樂，具太牢以為膳。鳥乃 眩視憂悲，不敢食一臠，不敢飲一杯，三日而死。此以己養養鳥也，非以鳥養養鳥 也。」此段文字乃警策世人：', '["意有所至而愛有所亡，可不慎邪", "其知適足以知人之過，而不知其所以過", "推其所欲以及於人，則恕之事而仁之術也", "視死生如來去。安時而處順，哀樂不能入也"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05371', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「夫至物微妙，可以理知，難以目識。譬猶豫章生七年，然後可覺耳。今以躁競之 心，涉希靜之塗，意速而事遲，望近而應遠，故莫能相終。夫悠悠者既以未效不求， 而求者以不專喪業；偏恃者以不兼無功，追術者以小道自溺。凡若此類，故欲之者， 萬無一能成也。」（嵇康〈養生論〉） 關於引文意涵，下列敘述何者正確？', '["精妙道理只能靠經驗得知，無法透過眼睛看見", "養生失敗的原因，在於急功躁進，無法始終如一", "生活悠閒的人不需要養生，因為心情輕鬆就不會生病", "太想追求養生之道，拋棄了該做的正事，反而會傷害生命"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05372', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '人情之所易忽莫如漸，天下之大可畏莫如漸。漸之始也，雖君子不以為意。有謂其 當防者，雖君子亦以為迂。不知其極重不反之勢，天地聖人亦無如之奈何，其所由 來者漸也。 下列選項最能適切說明本文旨意的是：', '["千里之堤，潰於蟻穴", "博觀約取，厚積薄發", "蓬生麻中，不扶而直", "輮以為輪，木不復挺"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05373', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「生平愛食之物，即可養身，不必再查《本草》。春秋之時並無《本草》，孔子性 嗜薑，即不撤薑食，性嗜醬，即不得其醬不食，皆隨性之所好，非有考據而然。孔 子於薑、醬二物，每食不離，未聞以多致疾。可見性好之物，多食不為祟也。但亦 有調劑君臣之法，不可不知。『肉雖多，不使勝食氣。』此即調劑君臣之法。」（李 漁《閑情偶寄．調飲啜第三》） 根據上文，下列敘述何者正確？', '["所謂「調劑君臣之法」，是指口腹之欲必須得到徹底的滿足", "養身之道與聖賢之道可相容並濟，相互參證，道即在日常生活中", "《本草》並非聖人所著之書，不可盡信，吾人心性即含天理，應反求諸己", "孔子於薑、醬二物，每食不離，在於聖人天性已具備調劑君臣之法，故能「從心 所欲，不踰矩」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05374', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列文句何者最適合用來闡述「一分耕耘，一分收穫」的道理？', '["不積蹞步，無以至千里；不積小流，無以成江海", "有為者辟若掘井，掘井九仞而不及泉，猶為棄井也", "不登高山，不知天之高也；不臨深谿，不知地之厚也", "人之所不學而能者，其良能也；所不慮而知者，其良知也"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05375', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「想要的很多；需要的不多」，關於這句名言，下列何者意旨最為接近？', '["一枝草，一點露", "偃鼠飲河，不過滿腹", "尺有所短，寸有所長", "身在江湖，心存魏闕"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05376', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '有貴人遊僧舍，酒酣，誦唐人詩云：「因過竹院逢僧話，又得浮生半日閑。」僧聞 而笑之。貴人問僧何笑，僧曰：「尊官得半日閑，老僧卻忙了三日。」（馮夢龍《古 今譚概．半日閑》）本文旨趣是：', '["說明寺僧俗不可耐", "肯定貴人閒適自在", "稱頌貴人超脫高雅性情", "冷諷貴人附庸風雅習氣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05377', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項抒發「物是人非」之感的是：', '["遲遲白日晚，嫋嫋秋風生。歲華盡搖落，芳意竟何成", "故國三千里，深宮二十年。一聲何滿子，雙淚落君前", "夕陽依舊壘，寒磐滿空林。惆悵南朝事，長江獨至今", "華實蔽野，黍稷盈疇。雖信美而非吾土兮，曾何足以少留"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05378', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '每個漁人心裡都埋藏著一幅屬於個人的海洋圖像，漁人點點滴滴累積與海洋接觸的 經驗來描繪這幅圖像。海洋波動不息變幻莫測，再細密精緻的圖像也難以完整描繪 海洋的性情和脾氣，一個曾經豐收的釣點，往往就是下回落空挫敗的場所。海洋是 如此的不可捉摸，漁人除了內心的這幅海洋圖像之外，仍須憑著「感覺」來與海洋 相對待。 依據上文，下列敘述何者正確？', '["漁人可藉由經驗完全探知魚訊流動的方向", "海洋的性情和脾氣不是人類理性所能掌握", "每個漁人內心對海洋的圖像可以瞭如指掌", "海洋波動不息、變幻莫測令漁人無法親近"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05379', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「我這時卻也開始了解到高山野花之所以多為多年生，原來有其苦衷。對許多高山 植物而言，籽苗內的養分畢竟有限，無法同時供應成長與孕育種子之需，所以為了 達成繁殖的目的，只得採取分年逐步完成生命循環的策略：第一年全心全意發展根 系，次年發芽，然後年復一年地儲存能量，待準備充足後，再驕傲地綻放出美麗的 花朵來。」下列何者最能說明野花開花之理？', '["天行健，君子以自強不息", "泰山不辭壤石，江海不逆小流，所以成大也", "源泉混混，不舍晝夜，盈科而後進，放乎四海", "求木之長者，必固其根本；欲流之遠者，必浚其泉源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
